solutions.javascript:
// Solution
function validateCommitMessage(message) {
    let parts = message.split('\n');
    let title = parts[0];
    let body = parts.slice(1).join('');
    return title !== '' && title.split('\n').length === 1 && body !== '';
}

solutions.python:
class Solution:
    def validateCommitMessage(self, message: str) -> bool:
        parts = message.split('\n');
        title = parts[0];
        body = '\n'.join(parts[1:]);
        return title != '' and title.count('\n') == 1 and body != '';
